   427→// for testing
   428→func (r *raftNode) pauseSending() {
   429→	p := r.transport.(rafthttp.Pausable)
   430→	p.Pause()
   431→}
   432→
   433→func (r *raftNode) resumeSending() {
   434→	p := r.transport.(rafthttp.Pausable)
   435→	p.Resume()
   436→}
