    15→package v3election
    16→
    17→import (
    18→	"context"
    19→	"errors"
    20→
    21→	clientv3 "go.etcd.io/etcd/client/v3"
    22→	"go.etcd.io/etcd/client/v3/concurrency"
    23→	epb "go.etcd.io/etcd/server/v3/etcdserver/api/v3election/v3electionpb"
    24→)
    25→
    26→// ErrMissingLeaderKey is returned when election API request
    27→// is missing the "leader" field.
    28→var ErrMissingLeaderKey = errors.New(`"leader" field must be provided`)
    29→
    30→type electionServer struct {
    31→	c *clientv3.Client
    32→	// we want compile errors if new methods are added
    33→	epb.UnsafeElectionServer
    34→}
    35→
    36→func NewElectionServer(c *clientv3.Client) epb.ElectionServer {
    37→	return &electionServer{c: c}
    38→}
    39→
    40→func (es *electionServer) Campaign(ctx context.Context, req *epb.CampaignRequest) (*epb.CampaignResponse, error) {
    41→	s, err := es.session(ctx, req.Lease)
    42→	if err != nil {
    43→		return nil, err
    44→	}
    45→	e := concurrency.NewElection(s, string(req.Name))
    46→	if err = e.Campaign(ctx, string(req.Value)); err != nil {
    47→		return nil, err
    48→	}
    49→	return &epb.CampaignResponse{
    50→		Header: e.Header(),
    51→		Leader: &epb.LeaderKey{
    52→			Name:  req.Name,
    53→			Key:   []byte(e.Key()),
    54→			Rev:   e.Rev(),
    55→			Lease: int64(s.Lease()),
    56→		},
    57→	}, nil
    58→}
    59→
    60→func (es *electionServer) Proclaim(ctx context.Context, req *epb.ProclaimRequest) (*epb.ProclaimResponse, error) {
    61→	if req.Leader == nil {
    62→		return nil, ErrMissingLeaderKey
    63→	}
    64→	s, err := es.session(ctx, req.Leader.Lease)
    65→	if err != nil {
    66→		return nil, err
    67→	}
    68→	e := concurrency.ResumeElection(s, string(req.Leader.Name), string(req.Leader.Key), req.Leader.Rev)
    69→	if err := e.Proclaim(ctx, string(req.Value)); err != nil {
    70→		return nil, err
    71→	}
    72→	return &epb.ProclaimResponse{Header: e.Header()}, nil
    73→}
    74→
    75→func (es *electionServer) Observe(req *epb.LeaderRequest, stream epb.Election_ObserveServer) error {
    76→	s, err := es.session(stream.Context(), -1)
    77→	if err != nil {
    78→		return err
    79→	}
    80→	e := concurrency.NewElection(s, string(req.Name))
    81→	ch := e.Observe(stream.Context())
    82→	for stream.Context().Err() == nil {
    83→		select {
    84→		case <-stream.Context().Done():
    85→		case resp, ok := <-ch:
    86→			if !ok {
    87→				return nil
    88→			}
    89→			lresp := &epb.LeaderResponse{Header: resp.Header, Kv: resp.Kvs[0]}
    90→			if err := stream.Send(lresp); err != nil {
    91→				return err
    92→			}
    93→		}
    94→	}
    95→	return stream.Context().Err()
    96→}
    97→
    98→func (es *electionServer) Leader(ctx context.Context, req *epb.LeaderRequest) (*epb.LeaderResponse, error) {
    99→	s, err := es.session(ctx, -1)
   100→	if err != nil {
   101→		return nil, err
   102→	}
   103→	l, lerr := concurrency.NewElection(s, string(req.Name)).Leader(ctx)
   104→	if lerr != nil {
   105→		return nil, lerr
   106→	}
   107→	return &epb.LeaderResponse{Header: l.Header, Kv: l.Kvs[0]}, nil
   108→}
   109→
   110→func (es *electionServer) Resign(ctx context.Context, req *epb.ResignRequest) (*epb.ResignResponse, error) {
   111→	if req.Leader == nil {
   112→		return nil, ErrMissingLeaderKey
   113→	}
   114→	s, err := es.session(ctx, req.Leader.Lease)
   115→	if err != nil {
   116→		return nil, err
   117→	}
   118→	e := concurrency.ResumeElection(s, string(req.Leader.Name), string(req.Leader.Key), req.Leader.Rev)
   119→	if err := e.Resign(ctx); err != nil {
   120→		return nil, err
   121→	}
   122→	return &epb.ResignResponse{Header: e.Header()}, nil
   123→}
   124→
   125→func (es *electionServer) session(ctx context.Context, lease int64) (*concurrency.Session, error) {
   126→	s, err := concurrency.NewSession(
   127→		es.c,
   128→		concurrency.WithLease(clientv3.LeaseID(lease)),
   129→		concurrency.WithContext(ctx),
   130→	)
   131→	if err != nil {
   132→		return nil, err
   133→	}
   134→	s.Orphan()
   135→	return s, nil
   136→}
